<?php
require_once __DIR__.'/functions.php';$member=require_member();$id=filter_input(INPUT_GET,'id',FILTER_VALIDATE_INT);$post=null;
if($id){$stmt=db()->prepare("SELECT * FROM posts WHERE id=? AND member_author_id=? AND post_type='community'");$stmt->execute([$id,$member['id']]);$post=$stmt->fetch();if(!$post){http_response_code(404);exit('Publicación no encontrada.');}}
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$postId=filter_input(INPUT_POST,'post_id',FILTER_VALIDATE_INT);$title=trim((string)($_POST['titulo']??''));$content=sanitize_html(trim((string)($_POST['contenido']??'')));$credit=trim((string)($_POST['image_credit']??''));try{if($title===''||trim(strip_tags($content))==='')throw new RuntimeException('El título y el contenido son obligatorios.');if(mb_strlen($credit)>200)throw new RuntimeException('El crédito no puede superar 200 caracteres.');$creditUrl=optional_http_url((string)($_POST['image_credit_url']??''));$image=upload_image($_FILES['imagen']??[]);if($postId){$stmt=db()->prepare("SELECT * FROM posts WHERE id=? AND member_author_id=? AND post_type='community'");$stmt->execute([$postId,$member['id']]);$existing=$stmt->fetch();if(!$existing)throw new RuntimeException('No puedes editar esta publicación.');db()->prepare("UPDATE posts SET titulo=?,contenido=?,imagen=?,image_credit=?,image_credit_url=?,author_name=?,status='pending' WHERE id=?")->execute([$title,$content,$image?:$existing['imagen'],$credit?:null,$creditUrl,$member['display_name'],$postId]);if($image)delete_image($existing['imagen']);}else{$slug=unique_post_slug($title);db()->prepare("INSERT INTO posts(titulo,slug,contenido,imagen,image_credit,image_credit_url,member_author_id,author_name,post_type,status) VALUES(?,?,?,?,?,?,?,?,'community','pending')")->execute([$title,$slug,$content,$image,$credit?:null,$creditUrl,$member['id'],$member['display_name']]);}flash('Publicación enviada a revisión.');redirect('/member-posts.php');}catch(Throwable $e){flash($e->getMessage(),'error');}}
render_header($post?'Editar publicación':'Publicar en la comunidad',['robots'=>'noindex,nofollow']);?><section class="panel"><h1><?=$post?'Editar publicación':'Nueva publicación'?></h1><p class="muted">Se publicará después de ser revisada.</p><form method="post" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><?php if($post):?><input type="hidden" name="post_id" value="<?=(int)$post['id']?>"><?php endif;?><label>Título<input name="titulo" maxlength="200" value="<?=e($_POST['titulo']??$post['titulo']??'')?>" required></label><label>Imagen de portada<input type="file" name="imagen" accept="image/png,image/jpeg,image/gif,image/webp"></label><div class="settings-grid"><label>Crédito de imagen<input name="image_credit" maxlength="200" value="<?=e($_POST['image_credit']??$post['image_credit']??'')?>" placeholder="Nombre del autor o fuente"></label><label>Enlace del crédito<input type="url" name="image_credit_url" maxlength="500" value="<?=e($_POST['image_credit_url']??$post['image_credit_url']??'')?>" placeholder="https://..."></label></div><?php render_editor($_POST['contenido']??$post['contenido']??'');?><button class="button">Enviar a revisión</button></form></section><?php render_footer();
